mapper.select:
SELECT
FROM mcp_gateway_tool
ORDER BY id DESC LIMIT #{offset}, #{pageSize}

mapper.delete:
DELETE
FROM mcp_gateway_tool
WHERE gateway_id = #{gatewayId}
  AND protocol_id = #{protocolId}
  AND tool_id = #{toolId}

mapper.select:
SELECT COUNT(1)
FROM mcp_gateway_tool
WHERE gateway_id = #{gatewayId}
  AND protocol_id = #{protocolId}
  AND tool_id = #{toolId}
LIMIT 1

mapper.update:
UPDATE mcp_gateway_tool
tool_name = #{toolName}, tool_type = #{toolType}, tool_status = #{toolStatus}, tool_description = #{toolDescription}, tool_version = #{toolVersion}, protocol_id = #{protocolId}, protocol_type = #{protocolType}, update_time = NOW()
WHERE gateway_id = #{gatewayId} AND protocol_id = #{protocolId} AND tool_id = #{toolId}

UPDATE mcp_gateway_tool
SET protocol_id   = #{protocolId},
    protocol_type = #{protocolType},
    update_time   = NOW()
WHERE gateway_id = #{gatewayId}
  AND tool_id = #{toolId}

mapper.select:
SELECT protocol_id
FROM mcp_gateway_tool
WHERE gateway_id = #{gatewayId}
  AND tool_name = #{toolName}
LIMIT 1

mapper.update:
UPDATE mcp_gateway_tool
SET tool_status = #{status},
    update_time = NOW(),
    version     = version + 1
WHERE gateway_id = #{gatewayId}
  AND protocol_id = #{protocolId}
  AND tool_id = #{toolId}
  AND version = #{oldVersion}

UPDATE mcp_gateway_tool
tool_name = #{po.toolName}, tool_type = #{po.toolType}, tool_status = #{po.toolStatus}, tool_description = #{po.toolDescription}, tool_version = #{po.toolVersion}, protocol_id = #{po.protocolId}, protocol_type = #{po.protocolType}, update_time = NOW(), version = version + 1
WHERE gateway_id = #{po.gatewayId} AND protocol_id = #{po.protocolId} AND tool_id = #{po.toolId} AND version = #{oldVersion}
